const texto = items[0].json.data;

if (!texto || !texto.trim()) {
  throw new Error('Arquivo da B3 veio vazio.');
}
function normalizarPeriodo(periodo) {
  const meses = {
    jan: '01',
    fev: '02',
    mar: '03',
    abr: '04',
    mai: '05',
    jun: '06',
    jul: '07',
    ago: '08',
    set: '09',
    out: '10',
    nov: '11',
    dez: '12'
  };

  const match = periodo.match(/^([A-Za-z]+)\/.*\/(\d{4})$/);

  if (!match) return periodo;

  const mes = meses[match[1].toLowerCase()];
  const ano = match[2];

  return `${ano}-${mes}`;
}
const linhas = texto
  .split(/\r?\n/)
  .map(l => l.trim())
  .filter(l => l.length > 0);

// Localiza a seção correta
const inicioSecao = linhas.findIndex(l =>
  l.toLowerCase().includes('movimenta') &&
  l.toLowerCase().includes('estrangeir')
);

if (inicioSecao === -1) {
  throw new Error('Seção de fluxo estrangeiro não encontrada.');
}

// Procura o cabeçalho da tabela
let cabecalhoIdx = -1;

for (let i = inicioSecao; i < Math.min(inicioSecao + 15, linhas.length); i++) {
  const l = linhas[i].toLowerCase();

  if (
    l.includes('compras') &&
    l.includes('vendas') &&
    l.includes('saldo')
  ) {
    cabecalhoIdx = i;
    break;
  }
}

if (cabecalhoIdx === -1) {
  throw new Error('Cabeçalho da tabela não encontrado.');
}

const parseLinha = (linha) => {
  return linha
    .split(';')
    .map(v => v.replace(/"/g, '').trim());
};

const cabecalho = parseLinha(linhas[cabecalhoIdx]);

const findCol = (...termos) =>
  cabecalho.findIndex(c =>
    termos.some(t =>
      c.toLowerCase().includes(t.toLowerCase())
    )
  );

const idxPeriodo = 0;
const idxCompras = findCol('compras', 'buyers');
const idxVendas = findCol('vendas', 'sellers');
const idxIPO = findCol('ipo', 'follow on');
const idxSaldo = findCol('saldo', 'balance');

if (
  idxCompras === -1 ||
  idxVendas === -1 ||
  idxSaldo === -1
) {
  throw new Error(
    'Não foi possível localizar as colunas principais.'
  );
}

function toNumber(valor) {
  if (!valor) return null;

  const numero = valor
    .replace(/\./g, '')
    .replace(',', '.')
    .replace(/[^\d.-]/g, '');

  return numero === '' ? null : Number(numero);
}

const regexMes =
  /^(jan|fev|mar|abr|mai|jun|jul|ago|set|out|nov|dez)/i;

const regexAno =
  /^\d{4}/;

const registros = [];

for (let i = cabecalhoIdx + 1; i < linhas.length; i++) {
  const linha = linhas[i];

  // Para quando chegar na próxima tabela histórica
  if (
    linha.toLowerCase().startsWith('ano / year')
  ) {
    break;
  }

  const cols = parseLinha(linha);

  if (cols.length < 2) {
    continue;
  }

  const periodo = cols[idxPeriodo]?.trim();

  if (!periodo) {
    continue;
  }

  // Aceita meses e linha acumulada do ano
  const ehMes = regexMes.test(periodo);
  const ehAnoAcumulado = periodo.includes('(*)');

  if (!ehMes && !ehAnoAcumulado) {
    continue;
  }

  registros.push({
    periodo: normalizarPeriodo(periodo),
    compras: toNumber(cols[idxCompras]),
    vendas: toNumber(cols[idxVendas]),
    ipo: idxIPO >= 0 ? toNumber(cols[idxIPO]) : 0,
    saldo: toNumber(cols[idxSaldo]),
  });
}

if (!registros.length) {
  throw new Error(
    'Nenhum registro de fluxo estrangeiro encontrado.'
  );
}

// Calcula acumulado progressivo
let acumulado = 0;

const resultado = registros.map(r => {
  if (!r.periodo.includes('(*)')) {
    acumulado += r.saldo || 0;
  }

  return {
    json: {
      ...r,
      saldo_acumulado: Number(acumulado.toFixed(2)),
      atualizado_em: new Date().toISOString()
    }
  };
});

console.log(
  `Fluxo estrangeiro processado: ${resultado.length} registros`
);

return resultado;

const total = items.length;
const periodos = items.map(i => i.json.periodo).join(', ');
console.log('Enviados: ' + total + ' registros');
return [{ json: { sucesso: true, total_enviados: total, periodos } }];
